#include <stdio.h>
#include <string.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    char buf[105];
    getchar(); // consume newline after T
    for(int i=0;i<T;i++){
        if(fgets(buf, sizeof(buf), stdin)==NULL) break;
        size_t len = strlen(buf);
        if(len>0 && buf[len-1]=='\n') buf[len-1]='\0';
        printf("Hello %s\n", buf);
    }
    return 0;
}

